import { createClient } from '@/lib/supabase/client';
import { useState, useEffect } from 'react';
import { DashboardLanguageProvider, useDashboardLanguage } from '@/i18n/DashboardLanguageContext';
import type { DashboardLanguage } from '@/i18n/dashboardTranslations';

// Language flag map for switcher
const LANG_FLAGS: Record<DashboardLanguage, string> = { pt: '🇧🇷', en: '🇺🇸', es: '🇪🇸' };
const LANG_ORDER: DashboardLanguage[] = ['pt', 'en', 'es'];

function DashboardShell({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const { t, language, setLanguage } = useDashboardLanguage();
  const [userName, setUserName] = useState('');
  const [isAdmin, setIsAdmin] = useState(false);
  const [branding, setBranding] = useState<{
    company_name: string; logo_url: string; brand_color: string; brand_accent: string; tagline: string;
  }>({ company_name: 'brieffy', logo_url: '', brand_color: '#ff6029', brand_accent: '#000000', tagline: 'simplify your requirements' });
  const [isOnboarded, setIsOnboarded] = useState(true);

  const isLoginPage = pathname === '/dashboard/login';
  const isRegisterPage = pathname === '/dashboard/register';
  const isOnboardingPage = pathname.startsWith('/dashboard/onboarding');

  useEffect(() => {
    async function loadUser() {
      const supabase = createClient();
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        const { data: profile } = await supabase
          .from('briefing_profiles')
          .select('display_name, company_name, logo_url, brand_color, brand_accent, tagline, is_admin, is_onboarded')
          .eq('id', user.id)
          .single();
        setUserName(profile?.display_name || user.email?.split('@')[0] || 'User');
        if (profile) {
          setIsAdmin(profile.is_admin || false);
          setIsOnboarded(profile.is_onboarded ?? false);
          setBranding({
            company_name: profile.company_name || 'brieffy',
            logo_url: profile.logo_url || '',
            brand_color: profile.brand_color || '#ff6029',
            brand_accent: profile.brand_accent || '#000000',
            tagline: profile.tagline || 'simplify your requirements',
          });

          // BUG-13 FIX: Prevent infinite onboarding redirect loop
          if (!profile.is_onboarded && !pathname.startsWith('/dashboard/onboarding')) {
            try {
              const justOnboarded = localStorage.getItem('brieffy_just_onboarded');
              if (justOnboarded) {
                const elapsed = Date.now() - parseInt(justOnboarded);
                if (elapsed < 30000) {
                  localStorage.removeItem('brieffy_just_onboarded');
                  setIsOnboarded(true);
                  return;
                }
                localStorage.removeItem('brieffy_just_onboarded');
              }
            } catch {}

            const { data: recheck } = await supabase
              .from('briefing_profiles')
              .select('is_onboarded')
              .eq('id', user.id)
              .single();

            if (recheck?.is_onboarded) {
              setIsOnboarded(true);
              return;
            }

            router.push('/dashboard/onboarding');
          }
        }
      }
    }
    if (!isLoginPage && !isRegisterPage) loadUser();
  }, [isLoginPage, isRegisterPage, pathname, router]);

  if (isLoginPage || isRegisterPage || isOnboardingPage) {
    return <>{children}</>;
  }

  const handleLogout = async () => {
    const supabase = createClient();
    await supabase.auth.signOut();
    router.push('/dashboard/login');
    router.refresh();
  };

  const navItems = [
    { href: '/dashboard/templates', icon: FileText, labelKey: 'nav.briefings', mobileLabel: 'Briefs', match: (p: string) => p === '/dashboard' || p.startsWith('/dashboard/templates') || !!p.match(/^\/dashboard\/[0-9a-f]/) },
    { href: '/dashboard/packages', icon: Package, labelKey: 'nav.aiPackages', mobileLabel: 'Skills', match: (p: string) => p.startsWith('/dashboard/packages') },
    { href: '/dashboard/profile', icon: User, labelKey: 'nav.myAccount', mobileLabel: 'Perfil', match: (p: string) => p.startsWith('/dashboard/profile') },
  ];

  const cycleLang = () => {
    const idx = LANG_ORDER.indexOf(language);
    const next = LANG_ORDER[(idx + 1) % LANG_ORDER.length];
    setLanguage(next);
  };

  return (
    <div suppressHydrationWarning className="min-h-screen bg-[var(--bg)] text-[var(--text)] font-sans flex flex-col md:flex-row">
      {/* ============ DESKTOP SIDEBAR ============ */}
      <aside className="hidden md:flex w-64 flex-shrink-0 bg-[var(--bg)] border-r border-[var(--bd)] flex-col justify-between">
        <div className="p-6">
          {/* Logo */}
          <Link href="/dashboard" className="flex items-center gap-3 mb-10 group">
            {branding.logo_url ? (
              <img
                src={branding.logo_url}
                alt={branding.company_name}
                className="w-10 h-10 rounded-xl object-contain bg-[var(--bg2)] border border-[var(--bd)] p-0.5 group-hover:scale-105 transition-transform"
              />
            ) : (
              <div
                className="w-10 h-10 rounded-xl flex items-center justify-center text-sm font-bold border border-[var(--bd)] bg-[var(--bg2)] text-[var(--text)] group-hover:scale-105 transition-transform"
              >
                {branding.company_name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase()}
              </div>
            )}
            <div>
              <h1 className="text-xl font-bold tracking-tight text-[var(--text)]">
                {branding.company_name}
                <span className="text-[var(--orange)]">.</span>
              </h1>
              {branding.tagline ? (
                <p className="text-[10px] text-[var(--text3)] uppercase tracking-widest font-medium truncate max-w-[150px]">{branding.tagline}</p>
              ) : (
                <p className="text-[10px] text-[var(--text3)] uppercase tracking-widest font-medium">{t('nav.aiPlatform')}</p>
              )}
            </div>
          </Link>

          {/* Nav Items */}
          <nav className="space-y-1.5 flex flex-col">
            {navItems.map(item => (
              <Link key={item.href} href={isOnboarded ? item.href : '#'}>
                <Button
                  variant="ghost"
                  disabled={!isOnboarded && !pathname.startsWith('/dashboard/onboarding')}
                  className={`w-full justify-start rounded-xl transition-all text-sm font-medium ${
                    item.match(pathname) 
                      ? 'bg-[var(--acbg)] text-[var(--actext)] border border-[var(--acbd)]' 
                      : 'text-[var(--text2)] hover:text-[var(--text)] hover:bg-[var(--bg2)]'
                  }`}
                >
                  <item.icon className="w-4 h-4 mr-3" />
                  {t(item.labelKey)}
                </Button>
              </Link>
            ))}
          </nav>
        </div>

        {/* User Info + Language + Logout */}
        <div className="p-6 border-t border-[var(--bd)] space-y-3">
          <div className="flex items-center gap-3 px-2">
            <div className="w-8 h-8 rounded-full bg-[var(--orange)] flex items-center justify-center text-xs font-bold text-black">
              {userName.charAt(0).toUpperCase()}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-[var(--text)] truncate">{userName}</p>
            </div>
            {/* Language Switcher */}
            <button
              onClick={cycleLang}
              title={`Language: ${language.toUpperCase()}`}
              className="w-8 h-8 rounded-lg bg-[var(--bg2)] border border-[var(--bd)] flex items-center justify-center text-sm hover:bg-[var(--bg3)] transition-colors cursor-pointer"
            >
              {LANG_FLAGS[language]}
            </button>
          </div>
          <Button
            variant="ghost"
            onClick={handleLogout}
            className="w-full justify-start rounded-xl text-[var(--text3)] hover:text-red-500 hover:bg-red-50"
          >
            <LogOut className="w-4 h-4 mr-3" />
            {t('nav.signOut')}
          </Button>
        </div>
      </aside>

      {/* ============ MOBILE TOP BAR ============ */}
      <div className="md:hidden bg-[var(--bg)] border-b border-[var(--bd)] px-4 py-3 flex items-center justify-between">
        <Link href="/dashboard" className="flex items-center gap-2">
          {branding.logo_url ? (
            <img src={branding.logo_url} alt={branding.company_name} className="w-6 h-6 rounded-lg object-contain" />
          ) : (
            <span className="font-bold text-lg text-[var(--text)]">
              {branding.company_name}<span className="text-[var(--orange)]">.</span>
            </span>
          )}
          {branding.logo_url && (
            <span className="font-bold text-lg text-[var(--text)]">{branding.company_name}</span>
          )}
        </Link>
        <div className="flex items-center gap-2">
          <button
            onClick={cycleLang}
            className="w-8 h-8 rounded-lg bg-[var(--bg2)] border border-[var(--bd)] flex items-center justify-center text-sm"
          >
            {LANG_FLAGS[language]}
          </button>
          <button
            onClick={handleLogout}
            className="w-8 h-8 rounded-lg bg-[var(--bg2)] border border-[var(--bd)] flex items-center justify-center text-sm text-[var(--text3)] hover:text-red-500 transition-colors"
            title="Logout"
          >
            <LogOut className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* ============ MAIN CONTENT ============ */}
      <main className="flex-1 overflow-x-hidden p-4 md:p-10 pb-24 md:pb-10">
        {children}
      </main>

      {/* ============ MOBILE BOTTOM TAB BAR ============ */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-[var(--bg)] border-t border-[var(--bd)] flex justify-around items-center px-2 py-1.5 safe-area-pb">
        {navItems.map(item => {
          const isActive = item.match(pathname);
          return (
            <Link
              key={item.href}
              href={isOnboarded ? item.href : '#'}
              className={`flex flex-col items-center gap-0.5 px-3 py-1.5 rounded-lg transition-colors min-w-[60px] ${
                isActive 
                  ? 'text-[var(--text)]' 
                  : 'text-[var(--text3)]'
              }`}
            >
              <item.icon className="w-5 h-5" />
              <span className="text-[9px] font-semibold tracking-wide uppercase">{item.mobileLabel}</span>
              {isActive && (
                <div className="w-1 h-1 rounded-full bg-[var(--orange)] mt-0.5" />
              )}
            </Link>
          );
        })}
      </nav>

      {/* Safe area spacing for iOS bottom */}
      <style jsx global>{`
        .safe-area-pb {
          padding-bottom: max(8px, env(safe-area-inset-bottom));
        }
      `}</style>
    </div>
  );
}

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  return (
    <DashboardLanguageProvider>
      <DashboardShell>{children}</DashboardShell>
    </DashboardLanguageProvider>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { Package, Plus, Pencil, Trash2, Save, X, GripVertical, Brain, Palette, Cpu, Megaphone, Headphones, DollarSign, Users, TrendingUp, Truck, Lightbulb, Shield, Server, ShoppingCart, Video, Sparkles, Globe, Lock } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { SKILL_TEMPLATES, type SkillTemplate } from '@/lib/skill-templates';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { createClient } from '@/lib/supabase/client';

const ICON_OPTIONS = [
  'Package', 'Brain', 'Palette', 'Cpu', 'Megaphone', 'Headphones', 
  'DollarSign', 'Users', 'TrendingUp', 'Truck', 'Lightbulb', 
  'Shield', 'Server', 'ShoppingCart', 'Video'
];

const ICON_MAP: Record<string, React.ElementType> = {
  Package, Brain, Palette, Cpu, Megaphone, Headphones, DollarSign, Users,
  TrendingUp, Truck, Lightbulb, Shield, Server, ShoppingCart, Video,
};

const DEPT_OPTIONS = [
  'branding', 'technology', 'marketing', 'operations', 'finance',
  'people', 'commercial', 'product', 'legal', 'digital', 'content', 'general'
];

interface CategoryPackage {
  slug: string;
  name: string;
  description: string;
  icon: string;
  system_prompt_fragment: string;
  max_questions: number | null;
  is_default_enabled: boolean;
  sort_order: number;
  department: string;
  skill_type?: 'official' | 'personal' | 'community';
  author_id?: string;
}

export default function PackagesPage() {
  const [packages, setPackages] = useState<CategoryPackage[]>([]);
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState<string | null>(null);
  const [creating, setCreating] = useState(false);
  const [saving, setSaving] = useState(false);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);

  const [form, setForm] = useState<Partial<CategoryPackage>>({});
  const [saveWarnings, setSaveWarnings] = useState<string[]>([]);
  const [activeTab, setActiveTab] = useState('official');

  const supabase = createClient();

  const verifyUserContext = useCallback(async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      setCurrentUserId(user.id);

      const { data: profile } = await supabase
        .from('briefing_profiles')
        .select('is_admin')
        .eq('id', user.id)
        .single();

      const adminRole = user.user_metadata?.role === 'admin' || user.app_metadata?.role === 'admin';
      setIsAdmin(adminRole || !!profile?.is_admin);
    } catch (err) {
      console.error('Error verifying user context:', err);
    }
  }, [supabase]);

  const fetchPackages = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/briefing/packages');
      if (res.ok) {
        const data = await res.json();
        setPackages(Array.isArray(data) ? data : []);
      }
    } catch (err) {
      console.error('Error fetching packages:', err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { 
    verifyUserContext();
    fetchPackages(); 
  }, [verifyUserContext, fetchPackages]);

  const officialSkills = packages.filter(p => !p.skill_type || p.skill_type === 'official');
  const personalSkills = packages.filter(p => p.skill_type === 'personal');

  const startCreate = () => {
    setCreating(true);
    setEditing(null);
    setForm({
      slug: '',
      name: '',
      description: '',
      icon: 'Brain',
      system_prompt_fragment: '',
      max_questions: 10,
      is_default_enabled: false,
      sort_order: packages.length,
      department: 'general',
      skill_type: isAdmin ? 'official' : 'personal'
    });
  };

  const startEdit = (pkg: CategoryPackage) => {
    setEditing(pkg.slug);
    setCreating(false);
    setForm({ ...pkg });
  };

  const cancelEdit = () => {
    setEditing(null);
    setCreating(false);
    setForm({});
  };

  const handleSave = async () => {
    setSaving(true);
    setSaveWarnings([]);
    try {
      let res: Response;
      if (creating) {
        res = await fetch('/api/briefing/packages', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(form),
        });
        if (!res.ok) throw new Error('Failed to create');
      } else if (editing) {
        res = await fetch('/api/briefing/packages', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ id: editing, ...form }),
        });
        if (!res.ok) throw new Error('Failed to update');
      } else {
        return;
      }

      const data = await res.json();
      if (data._warnings && data._warnings.length > 0) {
        setSaveWarnings(data._warnings);
        setTimeout(() => setSaveWarnings([]), 8000);
      }

      cancelEdit();
      fetchPackages();
      // Auto-switch to personal tab if the user created a personal skill
      if (form.skill_type === 'personal') setActiveTab('personal');
    } catch (err) {
      console.error(err);
      alert("Erro ao salvar a Skill.");
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (pkg: CategoryPackage) => {
    if (!confirm(`Tem certeza que deseja excluir a skill "${pkg.name}"?`)) return;
    try {
      await fetch(`/api/briefing/packages?id=${pkg.slug}`, { method: 'DELETE' });
      fetchPackages();
    } catch (err) {
      console.error(err);
      alert("Erro ao excluir skill.");
    }
  };

  const applySkillTemplate = (template: SkillTemplate) => {
    setForm({
      ...form,
      slug: template.suggested_slug,
      name: template.name,
      description: template.description,
      icon: template.icon,
      department: template.department,
      max_questions: template.max_questions,
      system_prompt_fragment: template.system_prompt_fragment,
    });
  };

  const renderForm = () => (
    <div className="space-y-4 p-6 bg-white border border-[var(--bd)] shadow-sm rounded-2xl animate-in fade-in slide-in-from-top-4 duration-300">
      <div className="flex justify-between items-start">
        <h3 className="text-lg font-bold text-gray-900">
          {creating ? '✨ Nova Skill de IA' : '✏️ Editar Skill'}
        </h3>
        {form.skill_type === 'personal' && (
          <span className="bg-amber-50 text-amber-600 px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1.5">
            <Lock className="w-3.5 h-3.5" /> Skill Privada
          </span>
        )}
      </div>

      {creating && (
        <div className="space-y-2 pb-2">
          <Label className="text-gray-500 text-xs uppercase tracking-wider flex items-center gap-1.5">
            <Sparkles className="w-3.5 h-3.5 text-[var(--orange)]" />
            Começar a partir de um Template Global
          </Label>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2">
            {SKILL_TEMPLATES.map((tpl) => {
              const TplIcon = ICON_MAP[tpl.icon] || Package;
              return (
                <button
                  key={tpl.id}
                  type="button"
                  onClick={() => applySkillTemplate(tpl)}
                  className="flex items-start gap-3 p-3 rounded-xl border border-gray-200 hover:border-[var(--orange)]/40 hover:bg-[var(--orange)]/5 transition-all text-left group"
                >
                  <div className="w-8 h-8 rounded-lg bg-gray-50 group-hover:bg-[var(--orange)]/10 flex items-center justify-center shrink-0 mt-0.5">
                    <TplIcon className="w-4 h-4 text-gray-400 group-hover:text-[var(--orange)]" />
                  </div>
                  <div className="min-w-0">
                    <p className="text-xs font-semibold text-gray-700 group-hover:text-gray-900 truncate">{tpl.name}</p>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <Label className="text-gray-500 text-xs uppercase tracking-wider">Identificador (Slug)</Label>
          <Input 
            value={form.slug || ''} 
            onChange={e => setForm({...form, slug: e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, '_')})}
            placeholder="ex: analise_mercado"
            className="bg-white border-gray-200 mt-1"
            disabled={!!editing && form.skill_type === 'official'}
          />
        </div>
        <div>
          <Label className="text-gray-500 text-xs uppercase tracking-wider">Nome da Skill</Label>
          <Input 
            value={form.name || ''} 
            onChange={e => setForm({...form, name: e.target.value})}
            placeholder="ex: Análise de Mercado"
            className="bg-white border-gray-200 mt-1"
          />
        </div>
      </div>

      <div>
        <Label className="text-gray-500 text-xs uppercase tracking-wider">Descrição Rápida</Label>
        <Input 
          value={form.description || ''} 
          onChange={e => setForm({...form, description: e.target.value})}
          placeholder="O que essa skill faz?"
          className="bg-white border-gray-200 mt-1"
        />
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div>
          <Label className="text-gray-500 text-xs uppercase tracking-wider">Ícone</Label>
          <select 
            value={form.icon || 'Brain'} 
            onChange={e => setForm({...form, icon: e.target.value})}
            className="w-full bg-white border border-gray-200 rounded-md text-gray-900 px-3 py-2 text-sm mt-1"
          >
            {ICON_OPTIONS.map(icon => (
              <option key={icon} value={icon}>{icon}</option>
            ))}
          </select>
        </div>
        <div>
          <Label className="text-gray-500 text-xs uppercase tracking-wider">Departamento</Label>
          <select 
            value={form.department || 'general'} 
            onChange={e => setForm({...form, department: e.target.value})}
            className="w-full bg-white border border-gray-200 rounded-md text-gray-900 px-3 py-2 text-sm mt-1"
          >
            {DEPT_OPTIONS.map(d => (
              <option key={d} value={d}>{d}</option>
            ))}
          </select>
        </div>
        <div>
          <Label className="text-gray-500 text-xs uppercase tracking-wider">Max Perguntas</Label>
          <Input 
            type="number"
            value={form.max_questions === null ? '' : (form.max_questions ?? 10)} 
            onChange={e => setForm({...form, max_questions: e.target.value === '' ? null : parseInt(e.target.value)})}
            placeholder="vazio = ilimitado"
            className="bg-white border-gray-200 mt-1"
          />
        </div>

        {isAdmin && form.skill_type === 'official' && (
          <div>
             <Label className="text-gray-500 text-xs uppercase tracking-wider text-red-500">Privilégio ADMIN</Label>
             <select 
               value={form.skill_type || 'official'}
               onChange={e => setForm({...form, skill_type: e.target.value as 'official' | 'personal'})}
               className="w-full bg-white border border-gray-200 rounded-md text-gray-900 px-3 py-2 text-sm mt-1 font-bold"
               disabled={!creating}
             >
               <option value="official">Global / Oficial</option>
               <option value="personal">Pessoal</option>
             </select>
          </div>
        )}
      </div>

      <div className="flex items-center gap-3">
        <Switch 
          checked={form.is_default_enabled ?? false}
          onCheckedChange={checked => setForm({...form, is_default_enabled: checked})}
          disabled={!isAdmin && form.skill_type !== 'personal'}
        />
        <Label className="text-gray-700 text-sm">
          Ativar por padrão em todas as sessões 
          {!isAdmin && " (Apenas admins podem forçar skills globais por padrão)"}
        </Label>
      </div>

      <div>
        <Label className="text-gray-500 text-xs uppercase tracking-wider">System Prompt (O Cérebro da Skill)</Label>
        <Textarea 
          value={form.system_prompt_fragment || ''} 
          onChange={e => setForm({...form, system_prompt_fragment: e.target.value})}
          placeholder="Comporte-se como um especialista em X. Você deve EXTRAIR as seguintes informações..."
          className="bg-white border-gray-200 mt-1 min-h-[250px] font-mono text-sm text-gray-800"
        />
        <span className="text-[10px] text-gray-500 mt-1 block">Este texto é injetado diretamente na IA quando o usuário escolhe usar esta skill. Seja imperativo.</span>
      </div>

      <div className="flex gap-2 justify-end pt-4 border-t border-gray-100">
        <Button variant="outline" className="border-gray-200 text-gray-600 hover:text-gray-900" onClick={cancelEdit}>
          <X className="w-4 h-4 mr-1" /> Cancelar
        </Button>
        <Button 
          className="bg-[var(--orange)] hover:bg-[#E65625] text-white"
          disabled={saving || !form.slug || !form.name || (form.system_prompt_fragment?.length ?? 0) < 10}
          onClick={handleSave}
        >
          <Save className="w-4 h-4 mr-1" /> {saving ? 'Salvando...' : 'Salvar Skill'}
        </Button>
      </div>
    </div>
  );

  const renderSkillList = (list: CategoryPackage[], isEditable: boolean) => {
    if (list.length === 0) {
      return (
        <div className="py-16 text-center text-gray-500 bg-[var(--bg2)] border border-dashed border-[var(--bd)] rounded-2xl">
          <Brain className="w-12 h-12 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-600 font-medium">Nenhuma Skill encontrada.</p>
          {isEditable && <p className="text-xs text-gray-400 mt-1">Clique em &quot;Nova Skill&quot; para criar a sua.</p>}
        </div>
      );
    }

    return (
      <div className="grid gap-3 sm:grid-cols-1 md:grid-cols-2 xl:grid-cols-3">
        {list.map((pkg, index) => {
          const IconComp = ICON_MAP[pkg.icon] || Brain;
          const canEdit = isEditable && (isAdmin || pkg.skill_type === 'personal');

          return (
            <div
              key={pkg.slug || `pkg-${index}`}
              className={`flex flex-col gap-3 p-5 rounded-2xl border transition-all ${
                editing === pkg.slug 
                  ? 'border-[var(--orange)] shadow-md bg-[var(--bg)]' 
                  : 'border-[var(--bd)] bg-[var(--bg2)] hover:border-gray-300 shadow-sm'
              }`}
            >
              <div className="flex justify-between items-start">
                <div className="w-12 h-12 rounded-xl bg-white border border-gray-100 flex items-center justify-center shrink-0 shadow-sm">
                  <IconComp className="w-6 h-6 text-gray-600" />
                </div>
                {canEdit ? (
                  <div className="flex gap-1">
                    <Button variant="ghost" size="sm" className="text-gray-400 hover:text-[var(--orange)] hover:bg-[var(--orange)]/10 h-8 w-8 p-0" onClick={() => startEdit(pkg)}>
                      <Pencil className="w-3.5 h-3.5" />
                    </Button>
                    <Button variant="ghost" size="sm" className="text-gray-400 hover:text-red-500 hover:bg-red-50 h-8 w-8 p-0" onClick={() => handleDelete(pkg)}>
                      <Trash2 className="w-3.5 h-3.5" />
                    </Button>
                  </div>
                ) : (
                  <div className="h-8 flex items-center">
                    <span className="text-[10px] font-semibold tracking-wider uppercase px-2 py-1 rounded bg-gray-100 text-gray-500">Somente Leitura</span>
                  </div>
                )}
              </div>

              <div className="flex-1 mt-1">
                <h4 className="text-base font-bold text-gray-900 group-hover:text-[var(--orange)] transition-colors">{pkg.name}</h4>
                <p className="text-xs text-gray-500 mt-1 line-clamp-2 md:line-clamp-3">{pkg.description}</p>
              </div>

              <div className="flex items-center justify-between mt-2 pt-3 border-t border-[var(--bd)]">
                <div className="flex gap-2">
                  <span className="text-[10px] text-gray-600 bg-white border border-gray-200 px-2 py-0.5 rounded-md font-medium">
                    {pkg.department}
                  </span>
                  {pkg.is_default_enabled && (
                    <span className="text-[10px] font-bold tracking-wider uppercase px-2 py-0.5 rounded-md bg-green-50 text-green-600 border border-green-200">
                      Auto
                    </span>
                  )}
                </div>
                <span className="text-xs text-gray-400 font-mono">
                  {pkg.max_questions === null ? '∞' : `≤${pkg.max_questions}`} Q
                </span>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="p-4 md:p-8 space-y-8 animate-in fade-in duration-500 max-w-[1600px] mx-auto min-h-screen pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-[var(--bg2)] p-6 rounded-3xl border border-[var(--bd)] shadow-sm">
        <div>
          <h1 className="text-2xl md:text-3xl font-outfit font-bold text-gray-900 flex items-center gap-3">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-[var(--orange)] to-rose-500 shadow-md flex items-center justify-center shrink-0">
              <Brain className="w-6 h-6 text-white" />
            </div>
            Skills de IA
          </h1>
          <p className="text-gray-500 text-sm mt-2 max-w-xl">
            As Skills são personalidades da IA que direcionam o resultado do briefing para o seu negócio.
            Explore habilidades prontas ou crie as suas próprias.
          </p>
        </div>
        <Button 
          className="bg-[var(--orange)] hover:bg-[#E65625] text-white shadow-sm h-12 px-6 rounded-xl shrink-0"
          onClick={startCreate}
          disabled={creating}
        >
          <Plus className="w-5 h-5 mr-2" /> {isAdmin ? 'Nova Skill' : 'Criar Minha Skill'}
        </Button>
      </div>

      {/* Validation Warnings */}
      {saveWarnings.length > 0 && (
        <div className="p-4 rounded-xl border border-amber-500/30 bg-amber-50 shadow-sm space-y-1 animate-in fade-in duration-300">
          <p className="text-xs font-semibold text-amber-800">Skill salvo com observações:</p>
          {saveWarnings.map((w, i) => (
            <p key={i} className="text-xs text-amber-600">• {w}</p>
          ))}
        </div>
      )}

      {/* Create/Edit Form */}
      {(creating || editing) && renderForm()}

      {/* Skills Tabs */}
      {!creating && !editing && (
        <Tabs defaultValue="official" value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="bg-gray-100/60 border border-gray-200 p-1.5 rounded-2xl h-14 w-full max-w-md mx-auto grid grid-cols-3 mb-8">
            <TabsTrigger value="official" className="rounded-xl h-full text-xs font-semibold data-[state=active]:bg-white data-[state=active]:text-[var(--orange)] data-[state=active]:shadow-sm transition-all focus:outline-none">
              ✨ Oficiais
            </TabsTrigger>
            <TabsTrigger value="personal" className="rounded-xl h-full text-xs font-semibold data-[state=active]:bg-white data-[state=active]:text-[var(--orange)] data-[state=active]:shadow-sm transition-all focus:outline-none">
              🧠 Minhas
            </TabsTrigger>
            <TabsTrigger value="community" className="rounded-xl h-full text-xs font-semibold data-[state=active]:bg-white data-[state=active]:text-[var(--orange)] data-[state=active]:shadow-sm transition-all focus:outline-none">
              🌍 Comunidade
            </TabsTrigger>
          </TabsList>

          <div className="mt-4">
            {loading ? (
              <div className="flex items-center justify-center py-20">
                <div className="w-10 h-10 border-4 border-[var(--orange)] border-t-transparent rounded-full animate-spin" />
              </div>
            ) : (
              <>
                <TabsContent value="official" className="animate-in fade-in slide-in-from-bottom-4 duration-500 focus-visible:outline-none">
                  <div className="mb-6 flex justify-between items-end">
                    <div>
                      <h2 className="text-xl font-bold font-outfit text-gray-900">Skills Globais da Brieffy</h2>
                      <p className="text-sm text-gray-500 mt-1">Especializações criadas e curadas pelo time oficial.</p>
                    </div>
                  </div>
                  {renderSkillList(officialSkills, true)}
                </TabsContent>

                <TabsContent value="personal" className="animate-in fade-in slide-in-from-bottom-4 duration-500 focus-visible:outline-none">
                  <div className="mb-6 flex justify-between items-end">
                    <div>
                      <h2 className="text-xl font-bold font-outfit text-gray-900">Suas Skills Privadas</h2>
                      <p className="text-sm text-gray-500 mt-1">Conhecimento sob medida criado por você para sua agência.</p>
                    </div>
                  </div>
                  {renderSkillList(personalSkills, true)}
                </TabsContent>

                <TabsContent value="community" className="animate-in fade-in slide-in-from-bottom-4 duration-500 focus-visible:outline-none">
                  <div className="py-20 text-center bg-gradient-to-b from-white to-[var(--bg2)] border border-[var(--bd)] rounded-3xl opacity-80">
                    <Globe className="w-16 h-16 text-[var(--orange)]/40 mx-auto mb-4" />
                    <h3 className="text-2xl font-bold font-outfit text-gray-900 mb-2">Comunidade Global Brieffy</h3>
                    <p className="text-gray-500 max-w-md mx-auto mb-6">
                      Em breve você poderá descobrir e usar Skills de IA criadas pelas mentes mais brilhantes do mercado.
                    </p>
                    <Button variant="outline" className="border-gray-200 pointer-events-none rounded-xl" disabled>
                      Coming Soon
                    </Button>
                  </div>
                </TabsContent>
              </>
            )}
          </div>
        </Tabs>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Save, Loader2, User, Building2, Lock, BarChart3, Sparkles, Palette, Upload, ImageIcon, Globe, Type, CheckCircle2, X, FileText } from 'lucide-react';
import { Textarea } from '@/components/ui/textarea';
import { createClient } from '@/lib/supabase/client';
import { useDashboardLanguage } from '@/i18n/DashboardLanguageContext';
import { toast } from 'sonner';

export default function ProfilePage() {
  const router = useRouter();
  const { t } = useDashboardLanguage();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [changingPassword, setChangingPassword] = useState(false);

  const [displayName, setDisplayName] = useState('');
  const [companyName, setCompanyName] = useState('');
  const [email, setEmail] = useState('');
  const [companySummary, setCompanySummary] = useState('');
  const [plan, setPlan] = useState('free');
  const [usedBriefings, setUsedBriefings] = useState(0);
  const [maxBriefings, setMaxBriefings] = useState(10);

  const [newPassword, setNewPassword] = useState('');
  const [passwordSuccess, setPasswordSuccess] = useState('');
  const [passwordError, setPasswordError] = useState('');

  // Branding state
  const [logoUrl, setLogoUrl] = useState('');
  const [brandColor, setBrandColor] = useState('#ff6029');
  const [brandAccent, setBrandAccent] = useState('#111111');
  const [tagline, setTagline] = useState('');
  const [website, setWebsite] = useState('');
  const [uploadingLogo, setUploadingLogo] = useState(false);
  const [savingBranding, setSavingBranding] = useState(false);
  const [brandingSaved, setBrandingSaved] = useState(false);
  const [dragOver, setDragOver] = useState(false);
  const logoInputRef = useRef<HTMLInputElement>(null);

  // Auto-save state
  const [autoSaved, setAutoSaved] = useState(false);
  const autoSaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isInitialLoadRef = useRef(true);

  // Auto-save effect
  useEffect(() => {
    if (isInitialLoadRef.current) return;
    if (!displayName && !companyName) return;

    if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);
    autoSaveTimerRef.current = setTimeout(async () => {
      try {
        const supabase = createClient();
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;
        await supabase.from('briefing_profiles').update({
          display_name: displayName,
          company_name: companyName,
          company_summary: companySummary,
          updated_at: new Date().toISOString(),
        }).eq('id', user.id);
        setAutoSaved(true);
        setTimeout(() => setAutoSaved(false), 3000);
      } catch {
        // Silent fail 
      }
    }, 2000);

    return () => {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);
    };
  }, [displayName, companyName, companySummary]);

  useEffect(() => {
    async function loadProfile() {
      const supabase = createClient();
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      setEmail(user.email || '');

      const { data: profile } = await supabase
        .from('briefing_profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      if (profile) {
        setDisplayName(profile.display_name || '');
        setCompanyName(profile.company_name || '');
        setCompanySummary(profile.company_summary || '');
        setPlan(profile.plan || 'free');
        setLogoUrl(profile.logo_url || '');
        setBrandColor(profile.brand_color || '#ff6029'); // Default to orange
        setBrandAccent(profile.brand_accent || '#111111');
        setTagline(profile.tagline || '');
        setWebsite(profile.website || '');
      }

      const { data: quota } = await supabase
        .from('briefing_quotas')
        .select('*')
        .eq('user_id', user.id)
        .single();

      if (quota) {
        setUsedBriefings(quota.used_briefings || 0);
        setMaxBriefings(quota.max_briefings || 3);
      }

      setLoading(false);
      setTimeout(() => { isInitialLoadRef.current = false; }, 100);
    }
    loadProfile();
  }, []);

  const handleSaveProfile = async () => {
    setSaving(true);
    try {
      const supabase = createClient();
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      await supabase
        .from('briefing_profiles')
        .update({
          display_name: displayName,
          company_name: companyName,
          company_summary: companySummary,
          updated_at: new Date().toISOString(),
        })
        .eq('id', user.id);

      router.refresh();
      toast.success('Perfil salvo com sucesso');
    } catch (err) {
      console.error('Error saving profile:', err);
      toast.error('Erro ao salvar perfil');
    } finally {
      setSaving(false);
    }
  };

  const handleChangePassword = async () => {
    if (newPassword.length < 6) {
      setPasswordError(t('profile.passwordMinError'));
      return;
    }

    setChangingPassword(true);
    setPasswordError('');
    setPasswordSuccess('');

    try {
      const supabase = createClient();
      const { error } = await supabase.auth.updateUser({ password: newPassword });
      if (error) throw error;
      setPasswordSuccess(t('profile.passwordSuccess'));
      setNewPassword('');
    } catch (err) {
      setPasswordError(err instanceof Error ? err.message : 'Failed to update password');
    } finally {
      setChangingPassword(false);
    }
  };

  const handleLogoUpload = useCallback(async (file: File) => {
    if (!file) return;
    const allowedTypes = ['image/png', 'image/jpeg', 'image/webp', 'image/svg+xml'];
    if (!allowedTypes.includes(file.type)) {
      toast.error(t('profile.logoTypeError'));
      return;
    }
    if (file.size > 2 * 1024 * 1024) {
      toast.error(t('profile.logoSizeError'));
      return;
    }

    setUploadingLogo(true);
    try {
      const formData = new FormData();
      formData.append('logo', file);
      const res = await fetch('/api/profile/upload-logo', { method: 'POST', body: formData });
      const data = await res.json();
      if (data.url) {
        setLogoUrl(data.url + '?t=' + Date.now()); 
      }
    } catch (err) {
      console.error('Logo upload failed:', err);
    } finally {
      setUploadingLogo(false);
    }
  }, [t]);

  const handleSaveBranding = async () => {
    setSavingBranding(true);
    setBrandingSaved(false);
    try {
      const res = await fetch('/api/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          logo_url: logoUrl,
          brand_color: brandColor,
          brand_accent: brandAccent,
          tagline,
          website,
          company_name: companyName,
        }),
      });
      if (res.ok) {
        setBrandingSaved(true);
        setTimeout(() => setBrandingSaved(false), 3000);
        router.refresh();
      }
    } catch (err) {
      console.error('Error saving branding:', err);
    } finally {
      setSavingBranding(false);
    }
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) handleLogoUpload(file);
  }, [handleLogoUpload]);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[50vh]">
        <Loader2 className="w-8 h-8 animate-spin text-[var(--orange)]" />
      </div>
    );
  }

  return (
    <div className="space-y-8 max-w-2xl animate-in fade-in duration-700">
      <div>
        <h2 className="text-2xl md:text-3xl font-extrabold tracking-tight text-[var(--text)]">
          {t('profile.title')}
        </h2>
        <p className="text-[var(--text2)] mt-1 font-medium">{t('profile.subtitle')}</p>
      </div>

      {/* Plan & Quota */}
      <Card className="bg-amber-50 border-amber-200 shadow-sm">
        <CardContent className="py-5 px-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-amber-100 flex items-center justify-center">
              <Sparkles className="w-5 h-5 text-amber-600" />
            </div>
            <div>
              <p className="font-bold text-amber-900 capitalize">{plan} {t('profile.plan')}</p>
              <p className="text-xs text-amber-700/80 font-medium">{t('profile.yourSubscription')}</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 text-sm">
              <BarChart3 className="w-4 h-4 text-amber-600" />
              <span className="text-amber-800 font-semibold">{usedBriefings}/{maxBriefings} {t('profile.briefingsUsed')}</span>
            </div>
            <div className="w-32 h-2 bg-amber-200/50 rounded-full overflow-hidden">
              <div 
                className="h-full bg-amber-500 rounded-full transition-all"
                style={{ width: `${Math.min((usedBriefings / maxBriefings) * 100, 100)}%` }}
              />
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Profile Info */}
      <Card className="bg-[var(--bg)] border-[var(--bd)] shadow-sm">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-[var(--text)] text-lg">
            <User className="w-5 h-5 text-[var(--orange)]" />
            {t('profile.profileInfo')}
          </CardTitle>
          <CardDescription className="text-[var(--text3)]">
            {t('profile.updateDetails')}
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-5">
          <div className="space-y-2">
            <Label className="text-[var(--text2)] font-semibold">{t('profile.email')}</Label>
            <Input value={email} disabled className="bg-[var(--bg2)] border-[var(--bd)] text-[var(--text3)]" />
            <p className="text-[11px] text-[var(--text3)]">{t('profile.emailCannotChange')}</p>
          </div>

          <div className="space-y-2">
            <Label className="text-[var(--text2)] font-semibold">{t('profile.displayName')}</Label>
            <Input
              value={displayName}
              onChange={(e) => setDisplayName(e.target.value)}
              className="bg-[var(--bg)] border-[var(--bd)] focus-visible:ring-[var(--orange)] focus-visible:border-[var(--orange)]"
            />
          </div>

          <div className="space-y-2">
            <Label className="text-[var(--text2)] font-semibold flex items-center gap-1.5">
              <Building2 className="w-3.5 h-3.5" />
              {t('profile.companyName')}
            </Label>
            <Input
              value={companyName}
              onChange={(e) => setCompanyName(e.target.value)}
              placeholder={t('profile.companyPlaceholder')}
              className="bg-[var(--bg)] border-[var(--bd)] focus-visible:ring-[var(--orange)] focus-visible:border-[var(--orange)]"
            />
          </div>

          <div className="space-y-2">
            <Label className="text-[var(--text2)] font-semibold flex items-center gap-1.5">
              <FileText className="w-3.5 h-3.5" />
              {t('profile.operationalSummary')}
            </Label>
            <Textarea
              value={companySummary}
              onChange={(e) => setCompanySummary(e.target.value)}
              placeholder={t('profile.summaryPlaceholder')}
              className="bg-[var(--bg)] border-[var(--bd)] focus-visible:ring-[var(--orange)] focus-visible:border-[var(--orange)] min-h-[150px] text-sm"
            />
            <p className="text-[11px] text-[var(--text3)] mt-1">
              {t('profile.summaryHelp')}
            </p>
          </div>

          <div className="flex items-center gap-3 pt-2">
            <span className={`text-xs text-emerald-600 font-medium flex items-center gap-1.5 transition-opacity duration-500 ${autoSaved ? 'opacity-100' : 'opacity-0'}`}>
              <CheckCircle2 className="w-3.5 h-3.5" />
              {t('profile.autoSaved')}
            </span>
            <Button onClick={handleSaveProfile} disabled={saving} className="bg-[var(--text)] hover:opacity-90 text-[var(--bg)] btn-pill font-semibold px-6 ml-auto">
              {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
              {t('profile.saveProfile')}
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Branding & Customization */}
      <Card className="bg-[var(--bg)] border-[var(--bd)] shadow-sm overflow-hidden">
        <CardHeader className="relative border-b border-[var(--bd)] bg-[var(--bg2)] pb-4">
          <CardTitle className="flex items-center gap-2 text-[var(--text)] relative z-10 text-lg">
            <Palette className="w-5 h-5 text-[var(--orange)]" />
            {t('profile.brandingTitle')}
          </CardTitle>
          <CardDescription className="text-[var(--text3)] relative z-10 mt-1">
            {t('profile.brandingDesc')}
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6 pt-6">
          {/* Logo Upload */}
          <div className="space-y-3">
            <Label className="text-[var(--text2)] font-semibold flex items-center gap-1.5">
              <ImageIcon className="w-3.5 h-3.5" />
              {t('profile.companyLogo')}
            </Label>
            <div className="flex flex-col sm:flex-row items-center sm:items-start gap-4">
              {/* Logo Preview */}
              <div className="shrink-0">
                {logoUrl ? (
                  <div className="relative group">
                    <img
                      src={logoUrl}
                      alt="Logo"
                      className="w-24 h-24 rounded-2xl object-cover bg-white border border-[var(--bd)] shadow-sm p-1"
                    />
                    <button
                      onClick={() => setLogoUrl('')}
                      className="absolute -top-2 -right-2 w-7 h-7 bg-red-100 border border-red-200 text-red-600 rounded-full flex items-center justify-center transition-all hover:bg-red-200"
                    >
                      <X className="w-3.5 h-3.5" />
                    </button>
                  </div>
                ) : (
                  <div
                    className="w-24 h-24 rounded-2xl flex items-center justify-center text-2xl font-bold border border-[var(--bd)] shadow-sm bg-[var(--bg2)]"
                    style={{ color: brandColor }}
                  >
                    {(companyName || 'AI').split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase()}
                  </div>
                )}
              </div>

              {/* Drop Zone */}
              <div
                className={`flex-1 w-full border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${
                  dragOver
                    ? 'border-[var(--orange)] bg-[#ff6029]/5'
                    : 'border-[var(--bd-strong)] hover:border-[var(--orange)] hover:bg-[var(--bg2)]'
                }`}
                onClick={() => logoInputRef.current?.click()}
                onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
                onDragLeave={() => setDragOver(false)}
                onDrop={handleDrop}
              >
                <input
                  ref={logoInputRef}
                  type="file"
                  accept="image/png,image/jpeg,image/webp,image/svg+xml"
                  className="hidden"
                  onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) handleLogoUpload(file);
                  }}
                />
                {uploadingLogo ? (
                  <div className="flex flex-col items-center gap-2 py-2">
