                  />
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={addSignal}
                    disabled={!newSignal.trim()}
                    className="h-10 px-3 border-amber-500/20 text-amber-400 hover:bg-amber-500/10 rounded-xl shrink-0"
                  >
                    <Plus className="w-4 h-4" />
                  </Button>
                </div>
              </div>

              {/* ── Context (Collapsible) ────── */}
              <div className="space-y-2">
                <button
                  type="button"
