interface TypeformWizardProps {
  hasAccessPassword?: boolean;
  accessSessionId?: string;
}

export function TypeformWizard({ hasAccessPassword = false, accessSessionId }: TypeformWizardProps) {
  const {
    messages,
    currentStepIndex,
    goBack,
    submitAnswer,
    isLoading,
    isGeneratingMore,
    generateMoreOptions,
    isUploadStep,
    chosenLanguage,
    generatedDocument,
    isGeneratingDocument,
    documentError,
    generateDocument,
    branding,
    editToken,
    editPassphrase,
    selectedPackageDetails,
    basalInfo,
    isOwner,
    isOnboarding,
    detectedSignals,
    engagementLevel,
  } = useBriefing();

  const [inputText, setInputText] = useState("");
  const [isRecording, setIsRecording] = useState(false);
  const [showSplash, setShowSplash] = useState(true);
  const [accessUnlocked, setAccessUnlocked] = useState(!hasAccessPassword);

  const mainRef = useRef<HTMLElement>(null);
  const prevStepRef = useRef(currentStepIndex);
  const [direction, setDirection] = useState<1 | -1>(1);

  const activeMessage = messages[currentStepIndex];
  const isFinished = !!generatedDocument;
  const isDiscoveryPhase = currentStepIndex === 0;

  const t = (I18N[chosenLanguage] || I18N.pt) as any;

  const activeColor = useMemo(() => {
    return branding.brand_color || '#171717';
  }, [branding.brand_color]);

  const activeFont = useMemo(() => {
    return (branding.brand_font && branding.brand_font !== 'Outfit') ? branding.brand_font : 'DM Sans';
  }, [branding.brand_font]);

  const activeCompanyName = useMemo(() => {
    // If it's the generic placeholder, prioritize a cleaner brand name
    if (branding.company_name === 'Sua Empresa') return 'Brieffy';
    return branding.company_name || 'Brieffy';
  }, [branding.company_name]);

  useEffect(() => {
    if (currentStepIndex > prevStepRef.current) setDirection(1);
    else if (currentStepIndex < prevStepRef.current) setDirection(-1);
    prevStepRef.current = currentStepIndex;
  }, [currentStepIndex]);

  const displayProgress = useMemo(() => {
    if (isFinished || isUploadStep) return 100;
    const rawPct = (basalInfo.basalCoverage || 0) * 100;
    const skillCount = selectedPackageDetails?.length || 0;
    const skillDilution = 1 / (1 + skillCount * 0.22);
    const dilutedBasal = rawPct * skillDilution;
    const stepsFloor = Math.min(currentStepIndex * 4, 92);
    const combined = Math.max(dilutedBasal, stepsFloor);
    const capped = Math.min(Math.round(combined), 95);
    return Math.max(capped, 3);
  }, [isFinished, isUploadStep, basalInfo.basalCoverage, selectedPackageDetails?.length, currentStepIndex]);

  const handleSend = useCallback((text?: string) => {
    const val = text !== undefined ? text : inputText;
    if (!val.trim()) return;
    submitAnswer(val);
    setInputText("");
  }, [inputText, submitAnswer]);

  const handleAccessUnlocked = useCallback(() => {
    setAccessUnlocked(true);
  }, []);

  const dismissSplash = useCallback(() => setShowSplash(false), []);

  // Early return if no message (safety)
  if (!activeMessage && !isUploadStep && !isFinished) {
     return (
       <div className="h-full w-full flex items-center justify-center bg-[var(--bg)]">
          <RefreshCw className="w-6 h-6 animate-spin text-[var(--orange)]" />
       </div>
     );
  }

  // ==========================
  //  CONTENT RENDERERS
  // ==========================

  const renderContent = () => {
    // 1. FINISHED STATE (Document Editor)
    if (isFinished) {
      return (
        <motion.div
          key="finished-view"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="flex flex-col h-full bg-white"
        >
          <DocumentEditor 
            initialContent={generatedDocument!} 
            onSave={async (newContent) => {
               const res = await fetch("/api/document/save", {
                 method: "POST",
                 headers: { "Content-Type": "application/json" },
                 body: JSON.stringify({
                   editToken,
                   passphrase: editPassphrase,
                   documentContent: newContent
                 })
               });
               if (!res.ok) throw new Error("Erro ao salvar.");
            }}
          />
        </motion.div>
      );
    }

    // 2. UPLOAD/GENERATE STATE
    if (isUploadStep || isGeneratingDocument) {
      return (
        <motion.div
          key="upload-view"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -20 }}
          className="flex-1 flex flex-col items-center justify-center p-6 text-center space-y-8"
        >
          {isGeneratingDocument ? (
            <div className="space-y-6">
               <AIThinkingAnimation 
                  language={chosenLanguage} 
                  brandColor={activeColor}
                  accentColor={branding.brand_accent || '#000000'}
                />
                <h2 className="text-2xl font-medium text-[var(--text)]">{t.generatingDoc}</h2>
                <p className="text-gray-500 max-w-sm mx-auto">
                  {t.analyzingResponses.replace('{count}', messages.length.toString())}
                </p>
            </div>
          ) : (
            <>
              <div className="space-y-4">
                <h1 className="text-3xl md:text-5xl font-medium tracking-tight text-[var(--text)] leading-tight" style={{ fontFamily: '"DM Sans", sans-serif' }}>
                  {documentError ? 'Algo deu errado' : t.allSet}
                </h1>
                <p className="text-lg text-gray-500 max-w-lg mx-auto leading-relaxed">
                  {documentError ? documentError : t.uploadRef}
                </p>
              </div>

              <div className={`w-24 h-24 rounded-full flex items-center justify-center ${documentError ? 'bg-red-50' : 'bg-[var(--orange)]/10'}`}>
                {documentError ? <span className="text-4xl">⚠️</span> : <Sparkles className="w-10 h-10 text-[var(--orange)]" />}
              </div>

              <Button 
                onClick={generateDocument}
                className={`w-full max-w-md h-16 text-lg font-bold rounded-full transition-all ${
                  documentError ? 'bg-red-600 text-white' : 'bg-[var(--orange)] text-black hover:opacity-90'
                }`}
              >
                {documentError ? 'Tentar Novamente' : <>{t.generateDiag} <ArrowRight className="w-5 h-5 ml-2" /></>}
              </Button>
            </>
          )}
        </motion.div>
      );
    }

    // 3. WIZARD FLOW
    return (
      <motion.div
        key={`step-${currentStepIndex}`}
        initial={{ opacity: 0, x: direction > 0 ? 60 : -60 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, x: direction > 0 ? -60 : 60, scale: 0.98 }}
        transition={{ duration: 0.45, ease: [0.22, 1, 0.36, 1] }}
        className="flex-1 flex flex-col p-6 overflow-y-auto"
      >
        <div className="max-w-3xl mx-auto w-full flex flex-col space-y-8 md:space-y-12 py-12">
           {/* Discovery Badge */}
           {isDiscoveryPhase && (
              <motion.div
                initial={{ opacity: 0, y: -8 }}
                animate={{ opacity: 1, y: 0 }}
                className="inline-flex items-center gap-2.5 px-4 py-2.5 rounded-full bg-[var(--orange)]/5 border border-[var(--orange)]/20 text-[var(--orange)] text-sm font-medium w-fit"
              >
                <span className="w-2 h-2 rounded-full bg-[var(--orange)] animate-pulse" />
                {chosenLanguage === 'en' ? 'Speak freely — the more details, the better' : 'Fale livremente — quanto mais detalhes, melhor'}
              </motion.div>
            )}

            {/* Micro-feedback */}
            {activeMessage?.microFeedback && (
              <motion.div
                initial={{ opacity: 0, y: 12 }}
                animate={{ opacity: 1, y: 0 }}
                className="inline-flex items-start gap-2.5 px-4 py-3 rounded-2xl bg-white border border-gray-200 shadow-sm w-fit max-w-md"
              >
                <span className="w-1.5 h-1.5 rounded-full bg-[var(--orange)] mt-2 shrink-0" />
                <span className="text-[13px] text-gray-500 font-medium">{activeMessage.microFeedback}</span>
              </motion.div>
            )}

            {/* Question Text */}
            <h1 
              className="text-2xl md:text-5xl font-medium tracking-tight text-[var(--text)] leading-tight"
              style={{ fontFamily: `"${activeFont}", sans-serif` }}
            >
              {activeMessage?.content}
            </h1>

            {/* Input Area */}
            <div className="w-full">
              {isLoading ? (
                <AIThinkingAnimation 
                  language={chosenLanguage} 
                  brandColor={activeColor}
                  accentColor={branding.brand_accent || '#000000'}
                />
              ) : (
                <DynamicInput 
                  activeMessage={activeMessage}
                  inputText={inputText}
                  setInputText={setInputText}
                  submitAnswer={submitAnswer}
                  handleSend={handleSend}
                  isLoading={isLoading}
                  isRecording={isRecording}
                  setIsRecording={setIsRecording}
                  generateMoreOptions={generateMoreOptions}
                  isGeneratingMore={isGeneratingMore}
                  voiceLanguage={chosenLanguage}
                  messages={messages}
                  isDiscoveryPhase={isDiscoveryPhase}
                />
              )}
            </div>

            {/* Actions / Navigation */}
            {!isLoading && currentStepIndex > 0 && !isDiscoveryPhase && (
              <div className="flex items-center justify-between pt-4">
                <Button 
                  variant="ghost" 
                  onClick={goBack}
                  className="text-gray-500 hover:text-black rounded-full px-6 h-12"
                >
                  <ArrowLeft className="w-4 h-4 mr-2" />
                  {t.goBackAdjust}
                </Button>
                <Button 
                  variant="ghost" 
                  onClick={() => submitAnswer('(skipped)')}
                  className="text-gray-400 hover:text-gray-600 rounded-full px-6 h-12 text-sm"
                >
                  {chosenLanguage === 'en' ? 'Skip' : 'Pular'}
                </Button>
              </div>
            )}
        </div>
      </motion.div>
    );
  };

  return (
    <div 
      className="h-full w-full relative overflow-hidden bg-[var(--bg)]"
      style={{ fontFamily: '"DM Sans", sans-serif' }}
    >
      <AnimatePresence mode="wait">
        {showSplash && (
          <AILoadingSplash
            key="splash"
            branding={{
              logo_url: branding.logo_url,
              company_name: activeCompanyName,
              brand_color: branding.brand_color,
              brand_accent: branding.brand_accent,
              tagline: branding.tagline,
            }}
            language={chosenLanguage}
            skillCount={selectedPackageDetails?.length || 0}
            requirePassword={hasAccessPassword && !accessUnlocked}
            sessionId={accessSessionId}
            onAccessUnlocked={handleAccessUnlocked}
            onComplete={dismissSplash}
          />
        )}
      </AnimatePresence>

      {!showSplash && (
        <div className="flex flex-col h-full">
          {/* Header */}
          <header className="flex items-center justify-between p-4 md:px-8 h-20 shrink-0 border-b border-[var(--bd)]">
            <div className="flex items-center gap-4">
              {currentStepIndex > 0 && !isFinished && (
                <Button variant="ghost" size="icon" onClick={goBack} className="rounded-full w-10 h-10 border border-[var(--bd)] bg-white text-black hover:bg-gray-50">
                  <ArrowLeft className="w-5 h-5" />
                </Button>
              )}
              <div className="flex items-center gap-3">
                 <BrandedLogo branding={{ ...branding, brand_color: activeColor, company_name: activeCompanyName }} size="sm" isSolid />
                 <span className="font-bold text-sm hidden sm:block">{activeCompanyName}</span>
              </div>
            </div>

            <div className="flex items-center gap-4">
              {/* Progress Pill */}
              {!isFinished && (
                <div className="px-4 py-1.5 rounded-full bg-[#FFF2ED] text-[var(--orange)] text-xs font-bold border border-[#FFCFBC]">
                  {displayProgress}%
                </div>
              )}
              <BriefingActionsMenu isOwner={!!isOwner} isOnboarding={!!isOnboarding} />
            </div>
          </header>

          {/* Progress Line */}
          {!isFinished && (
            <div className="h-1 bg-gray-100 w-full shrink-0 relative overflow-hidden">
               <motion.div 
                 className="h-full bg-[var(--orange)]"
                 initial={{ width: 0 }}
                 animate={{ width: `${displayProgress}%` }}
                 transition={{ duration: 0.8, ease: "easeOut" }}
               />
            </div>
          )}

          {/* Main Content */}
          <main className="flex-1 overflow-hidden relative flex flex-col">
            <AnimatePresence mode="wait">
              {renderContent()}
            </AnimatePresence>
          </main>

          {/* Insights Panel */}
          <InsightsPanel signals={detectedSignals} isOwner={isOwner} />
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { ArrowRight, RefreshCw, Plus } from "lucide-react";
import { ScrollConfirmWrapper } from "@/components/briefing/ScrollConfirmWrapper";
import { TextAudioInput } from "./TextAudioInput";
import { CustomTextPills } from "./shared/CustomTextPills";
import { parseOption, isOtherOption } from "./constants";
import type { Message } from "@/lib/types";

interface CardSelectorInputProps {
  activeMessage: Message;
  inputText: string;
  setInputText: (t: string) => void;
  selectedMultiples: string[];
  setSelectedMultiples: (items: string[]) => void;
  handleLocalSend: () => void;
  handleAddCustomText: () => void;
  isLoading: boolean;
  isSubmittingLocal: boolean;
  generateMoreOptions: () => void;
  isGeneratingMore: boolean;
  voiceLanguage: string;
  isFontSelection: boolean;
  t: Record<string, string>;
}

export function CardSelectorInput({
  activeMessage,
  inputText,
  setInputText,
  selectedMultiples,
  setSelectedMultiples,
  handleLocalSend,
  handleAddCustomText,
  isLoading,
  isSubmittingLocal,
  generateMoreOptions,
  isGeneratingMore,
  voiceLanguage,
  isFontSelection,
  t,
}: CardSelectorInputProps) {
  const options = activeMessage.options || [];
  const optionTitles = options.map((opt) => parseOption(opt, 0).text);
  const customTexts = selectedMultiples.filter((item) => !optionTitles.includes(item));
  const [highlightInput, setHighlightInput] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const scrollTargetRef = useRef<HTMLDivElement>(null);

  const hasOtherSelected = selectedMultiples.some(isOtherOption);
  const isTextInputVisible = showTextInput || hasOtherSelected || customTexts.length > 0 || inputText.trim().length > 0;

  const specifyLabel = voiceLanguage === "pt"
    ? "Especifique abaixo o que deseja:"
    : voiceLanguage === "es"
    ? "Especifique a continuación lo que desea:"
    : "Specify below what you want:";

  const handleCardClick = (title: string) => {
    const isSelected = selectedMultiples.includes(title);
    if (isSelected) {
      setSelectedMultiples(selectedMultiples.filter((t) => t !== title));
      if (isOtherOption(title)) {
        setShowTextInput(false);
      }
    } else {
      setSelectedMultiples([...selectedMultiples, title]);
      // If it's an "Other" option, redirect to text input
      if (isOtherOption(title)) {
        setShowTextInput(true);
        setHighlightInput(true);
        setTimeout(() => setHighlightInput(false), 2000);
        setTimeout(() => scrollTargetRef.current?.scrollIntoView({ behavior: "smooth" }), 100);
      }
    }
  };

  return (
    <div className="flex flex-col gap-8 w-full mt-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
        {options.map((opt, idx) => {
          const optObj = typeof opt === "object" && opt !== null ? (opt as Record<string, unknown>) : null;
          const title = optObj
            ? String(optObj.title || optObj.name || optObj.label || JSON.stringify(opt))
            : String(opt);
          const desc = optObj ? String(optObj.description || "") : "";
          const isSelected = selectedMultiples.includes(title);

          return (
            <button
              key={idx}
              onClick={() => handleCardClick(title)}
              disabled={isLoading || isSubmittingLocal}
              className={`group flex flex-col items-start text-left p-4 md:p-8 rounded-3xl bg-white border transition-all min-h-[120px] md:min-h-auto active:scale-[0.98] ${
                isSelected
                  ? "border-[var(--orange)] bg-[var(--orange)]/5 shadow-[0_5px_30px_rgba(255,96,41,0.15)]"
                  : "border-gray-200 hover:border-[var(--orange)]/50 hover:bg-[var(--orange)]/5 hover:-translate-y-1 hover:shadow-lg"
              }`}
            >
              <div
                className={`w-10 h-10 md:w-12 md:h-12 shrink-0 rounded-2xl flex items-center justify-center mb-4 md:mb-6 transition-colors border ${
                  isSelected
                    ? "bg-[var(--orange)]/10 border-[var(--orange)]/50"
                    : "bg-gray-50 border-gray-200 group-hover:bg-[var(--orange)]/10"
                }`}
              >
                <div
                  className={`w-3 h-3 md:w-4 md:h-4 rounded-full transition-all ${
                    isSelected
                      ? "bg-[var(--orange)] shadow-sm"
                      : "bg-gray-300 group-hover:bg-[var(--orange)]"
                  }`}
                />
              </div>
              <h3
                className={`text-lg md:text-xl font-bold mb-2 md:mb-3 transition-colors ${
                  isSelected ? "text-[var(--orange)]" : "text-black group-hover:text-[var(--orange)]"
                }`}
                style={
                  isFontSelection
                    ? {
                        fontFamily: `"${title
                          .split("-")[0]
                          .replace(/[^a-zA-Z0-9 ]/g, "")
                          .trim()}", sans-serif`,
                        fontSize: "1.5rem",
                        fontWeight: 400,
                      }
                    : undefined
                }
              >
                {title}
              </h3>
              {desc && <p className="text-sm text-gray-500 font-inter leading-relaxed">{desc}</p>}
            </button>
          );
        })}
      </div>

      {activeMessage.allowMoreOptions && (
        <div className="flex justify-center w-full mt-2">
          <Button
            onClick={generateMoreOptions}
            disabled={isGeneratingMore}
            variant="outline"
            className="rounded-full gap-2 border-gray-200 bg-white shadow-sm text-[var(--orange)] hover:bg-gray-50 hover:text-[#e05221] h-14 px-8 w-full sm:w-auto"
          >
            <RefreshCw className={`w-4 h-4 ${isGeneratingMore ? "animate-spin" : ""}`} />
            <span>{t.suggestRoutes}</span>
          </Button>
        </div>
      )}

      <div ref={scrollTargetRef} className={`w-full transition-all mt-4 ${highlightInput ? 'opacity-100 ring-2 ring-[var(--orange)]/30 bg-[var(--orange)]/5 rounded-2xl p-2' : 'opacity-80 hover:opacity-100'}`}>
        <CustomTextPills
          customTexts={customTexts}
          onRemove={(text) => setSelectedMultiples(selectedMultiples.filter((t) => t !== text))}
        />
        {isTextInputVisible ? (
          <div className="w-full flex flex-col items-center mt-2 animate-in fade-in slide-in-from-top-2 duration-300">
            {highlightInput && (
              <p className="text-sm font-medium text-[var(--orange)] text-center animate-pulse mb-2">
                ↓ {specifyLabel}
              </p>
            )}
            <p className="text-sm text-center text-gray-500 mb-2">{t.addDetails}</p>
            <TextAudioInput
              inputText={inputText}
              setInputText={setInputText}
              onSubmit={handleLocalSend}
              onAction={handleAddCustomText}
              actionIcon={<Plus className="w-5 h-5" />}
              isAddAction
              isLoading={isLoading}
              isSubmittingLocal={isSubmittingLocal}
              selectedMultiplesCount={selectedMultiples.length}
              voiceLanguage={voiceLanguage}
            />
          </div>
        ) : (
          <div className="flex justify-center mt-2 animate-in fade-in">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowTextInput(true)}
              className="text-xs text-gray-400 hover:text-gray-600 rounded-full"
            >
              + {t.moreDetails || "Adicionar detalhes"}
            </Button>
          </div>
        )}
      </div>

      <ScrollConfirmWrapper
        containerClassName="flex flex-col sm:flex-row gap-4 w-full mt-6 items-center justify-end border-t border-gray-200 pt-6"
        isDisabled={
          (selectedMultiples.length === 0 && !inputText.trim()) || isLoading || isSubmittingLocal
        }
        ActionComponent={
          <Button
            size="lg"
            className={`w-full sm:w-auto h-14 px-8 rounded-full font-medium transition-all duration-300 border ${
              selectedMultiples.length > 0 || inputText.trim()
                ? "bg-black text-white hover:bg-neutral-800 shadow-xl hover:scale-105"
                : "bg-gray-100 text-gray-400 border-gray-200 hover:bg-gray-200"
            }`}
            onClick={handleLocalSend}
            disabled={
              (selectedMultiples.length === 0 && !inputText.trim()) || isLoading || isSubmittingLocal
            }
          >
            {isLoading || isSubmittingLocal ? (
              <RefreshCw className="w-5 h-5 mr-2 animate-spin text-white/70" />
            ) : null}
            {t.confirmSelection} <ArrowRight className="w-5 h-5 ml-2" />
          </Button>
        }
      />
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { ArrowRight, RefreshCw, Plus } from "lucide-react";
import { ScrollConfirmWrapper } from "@/components/briefing/ScrollConfirmWrapper";
import { TextAudioInput } from "./TextAudioInput";
import type { TextAudioInputHandle } from "./TextAudioInput";
import { CustomTextPills } from "./shared/CustomTextPills";
import { parseOption, isOtherOption } from "./constants";
import type { Message } from "@/lib/types";

interface MultipleChoiceInputProps {
  activeMessage: Message;
  inputText: string;
  setInputText: (text: string) => void;
  selectedMultiples: string[];
  setSelectedMultiples: (items: string[]) => void;
  handleLocalSend: () => void;
  handleAddCustomText: () => void;
  isLoading: boolean;
  isSubmittingLocal: boolean;
  voiceLanguage: string;
  t: Record<string, string>;
  isFontSelection: boolean;
}

export function MultipleChoiceInput({
  activeMessage,
  inputText,
  setInputText,
  selectedMultiples,
  setSelectedMultiples,
  handleLocalSend,
  handleAddCustomText,
  isLoading,
  isSubmittingLocal,
  voiceLanguage,
  t,
  isFontSelection,
}: MultipleChoiceInputProps) {
  const options = activeMessage.options || [];
  const [highlightInput, setHighlightInput] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const scrollTargetRef = useRef<HTMLDivElement>(null);
  const textInputRef = useRef<TextAudioInputHandle>(null);

  const optionTitles = options.map((opt) => parseOption(opt, 0).text);
  const customTexts = selectedMultiples.filter((item) => !optionTitles.includes(item));

  const hasOtherSelected = selectedMultiples.some(isOtherOption);
  const isTextInputVisible = showTextInput || hasOtherSelected || customTexts.length > 0 || inputText.trim().length > 0;

  const specifyLabel = voiceLanguage === "pt"
    ? "Especifique abaixo o que deseja:"
    : voiceLanguage === "es"
    ? "Especifique a continuación lo que desea:"
    : "Specify below what you want:";

  const handleCheckChange = (optText: string, checked: boolean | string) => {
    if (checked) {
      setSelectedMultiples([...selectedMultiples, optText]);
      // If it's an "Other" option, redirect to text input
      if (isOtherOption(optText)) {
        setShowTextInput(true);
        setHighlightInput(true);
        setTimeout(() => setHighlightInput(false), 2000);
        setTimeout(() => scrollTargetRef.current?.scrollIntoView({ behavior: "smooth" }), 100);
      }
    } else {
      setSelectedMultiples(selectedMultiples.filter((item) => item !== optText));
      if (isOtherOption(optText)) {
        setShowTextInput(false);
      }
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full mt-4">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
        {options.map((opt, idx) => {
          const { text: optText, key: optKey } = parseOption(opt, idx);
          const isSelected = selectedMultiples.includes(optText);
          return (
            <label
              key={optKey}
              className={`flex items-center gap-3 p-4 min-h-[48px] rounded-xl border cursor-pointer transition-all active:scale-[0.98] ${
                isSelected
                  ? "border-[var(--orange)] bg-[var(--orange)]/5 ring-1 ring-[var(--orange)]/30"
                  : "border-gray-200 bg-white hover:border-[var(--orange)]/30 shadow-sm"
              }`}
            >
              <Checkbox
                checked={isSelected}
                className="w-5 h-5 shrink-0 data-[state=checked]:bg-[var(--orange)] data-[state=checked]:border-[var(--orange)]"
                onCheckedChange={(checked) => handleCheckChange(optText, checked)}
              />
              <span
                className="text-black font-medium"
                style={
                  isFontSelection
                    ? {
                        fontFamily: `"${optText
                          .split("-")[0]
                          .replace(/[^a-zA-Z0-9 ]/g, "")
                          .trim()}", sans-serif`,
                        fontSize: "1.25rem",
                      }
                    : undefined
                }
              >
                {optText}
              </span>
            </label>
          );
        })}
      </div>

      <div ref={scrollTargetRef} className={`w-full transition-all mt-4 ${highlightInput ? 'opacity-100 ring-2 ring-[var(--orange)]/30 rounded-2xl p-2 bg-[var(--orange)]/5' : 'opacity-80 hover:opacity-100'}`}>
        <CustomTextPills
          customTexts={customTexts}
          onRemove={(text) =>
            setSelectedMultiples(selectedMultiples.filter((t) => t !== text))
          }
        />
        {isTextInputVisible ? (
          <div className="w-full flex flex-col items-center mt-2 animate-in fade-in slide-in-from-top-2 duration-300">
            {highlightInput && (
              <p className="text-sm font-medium text-[var(--orange)] text-center animate-pulse mb-2">
                ↓ {specifyLabel}
              </p>
            )}
            <p className="text-sm text-center text-gray-500 mb-2">
              {voiceLanguage === "pt"
                ? "Adicione detalhes via texto ou áudio (opcional):"
                : voiceLanguage === "es"
                ? "Agregue detalles vía texto o audio (opcional):"
                : "Add details via text or audio (optional):"}
            </p>
            <TextAudioInput
              ref={textInputRef}
              inputText={inputText}
              setInputText={setInputText}
              onSubmit={handleLocalSend}
              onAction={handleAddCustomText}
              actionIcon={<Plus className="w-5 h-5" />}
              isAddAction
              isLoading={isLoading}
              isSubmittingLocal={isSubmittingLocal}
              selectedMultiplesCount={selectedMultiples.length}
              voiceLanguage={voiceLanguage}
            />
          </div>
        ) : (
          <div className="flex justify-center mt-2 animate-in fade-in">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowTextInput(true)}
              className="text-xs text-gray-400 hover:text-gray-600 rounded-full"
            >
              + {t.moreDetails || "Adicionar detalhes"}
            </Button>
          </div>
        )}
      </div>

      <ScrollConfirmWrapper
        containerClassName="flex justify-end mt-6 border-t border-gray-200 pt-6"
        isDisabled={
          (selectedMultiples.length === 0 && !inputText.trim()) ||
          isLoading ||
          isSubmittingLocal
        }
        ActionComponent={
          <Button
            size="lg"
            className={`w-full sm:w-auto h-14 px-8 rounded-full font-medium transition-all duration-300 border ${
              selectedMultiples.length > 0 || inputText.trim()
                ? "bg-black text-white hover:bg-neutral-800 shadow-lg hover:scale-105"
                : "bg-gray-100 text-gray-400 border-gray-200 hover:bg-gray-200"
            }`}
            onClick={handleLocalSend}
            disabled={
              (selectedMultiples.length === 0 && !inputText.trim()) ||
              isLoading ||
              isSubmittingLocal
            }
          >
            {isLoading || isSubmittingLocal ? (
              <RefreshCw className="w-5 h-5 mr-2 animate-spin text-white/70" />
            ) : null}
            {t.confirmSelection} <ArrowRight className="w-5 h-5 ml-2" />
          </Button>
        }
      />
    </div>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { Button } from "@/components/ui/button";
import { RefreshCw } from "lucide-react";
import { ScrollConfirmWrapper } from "@/components/briefing/ScrollConfirmWrapper";
import { TextAudioInput } from "./TextAudioInput";
import type { TextAudioInputHandle } from "./TextAudioInput";
import { BottomSheetOptions } from "./BottomSheetOptions";
import { parseOption, isOtherOption } from "./constants";
import type { Message } from "@/lib/types";

const BOTTOM_SHEET_THRESHOLD = 5;

interface SingleChoiceInputProps {
  activeMessage: Message;
  inputText: string;
  setInputText: (text: string) => void;
  doSubmit: (val: string | string[] | number) => void;
  handleLocalSend: () => void;
  isLoading: boolean;
  isSubmittingLocal: boolean;
  generateMoreOptions: () => void;
  isGeneratingMore: boolean;
  voiceLanguage: string;
  t: Record<string, string>;
}

export function SingleChoiceInput({
  activeMessage,
  inputText,
  setInputText,
  doSubmit,
  handleLocalSend,
  isLoading,
  isSubmittingLocal,
  generateMoreOptions,
  isGeneratingMore,
  voiceLanguage,
  t,
}: SingleChoiceInputProps) {
  const [isMobile, setIsMobile] = useState(false);
  const [highlightInput, setHighlightInput] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const textInputRef = useRef<TextAudioInputHandle>(null);

  const hasOtherAnswered = activeMessage.userAnswer && typeof activeMessage.userAnswer === "string" && isOtherOption(activeMessage.userAnswer);
  const isTextInputVisible = showTextInput || hasOtherAnswered || inputText.trim().length > 0;

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768);
    check();
    window.addEventListener("resize", check);
    return () => window.removeEventListener("resize", check);
  }, []);

  const options = activeMessage.options || [];
  const msgText = activeMessage.content?.toLowerCase() || "";
  const isFontSelection =
    msgText.includes("tipografi") || (msgText.includes("fonte") && !msgText.includes("inspiraç"));

  // Load Google Fonts for font preview
  useEffect(() => {
    if (!isFontSelection) return;
    const fontNames = options
      .map((opt) => {
        const { text } = parseOption(opt, 0);
        return text.split(" - ")[0].trim().replace(/[^a-zA-Z0-9 ]/g, "");
      })
      .filter((n) => n && !n.toLowerCase().includes("nenhuma") && !n.toLowerCase().includes("none"));

    if (fontNames.length > 0) {
      const families = fontNames.map((n) => n.replace(/ /g, "+")).join("&family=");
      const linkId = "google-fonts-preview";
      if (!document.getElementById(linkId)) {
        const link = document.createElement("link");
        link.id = linkId;
        link.rel = "stylesheet";
        link.href = `https://fonts.googleapis.com/css2?family=${families}&display=swap`;
        document.head.appendChild(link);
      }
    }
  }, [isFontSelection, options]);

  const questionText = activeMessage.content || "";
  const companyMatch = questionText.match(
    /(?:represent[ae]|para|da|d[eo])\s+(?:a\s+|o\s+)?([A-ZÀ-Ú][a-zA-ZÀ-ú0-9]+(?:\s+[A-ZÀ-Ú][a-zA-ZÀ-ú0-9]+)*)/i
  );
  const companyPreview = companyMatch?.[1] || "Sua Marca";

  const useBottomSheet = isMobile && options.length > BOTTOM_SHEET_THRESHOLD && !isFontSelection;

  // Handler that intercepts "Other" options and redirects to text input
  const handleOptionClick = (optText: string) => {
    if (isOtherOption(optText)) {
      // Redirect to text/voice input instead of submitting
      setShowTextInput(true);
      setHighlightInput(true);
      setTimeout(() => setHighlightInput(false), 2000);
      setTimeout(() => textInputRef.current?.scrollIntoView(), 100);
      return;
    }
    doSubmit(optText);
  };

  // Handler for BottomSheet "Other" option — close sheet then redirect
  const handleBottomSheetSelect = (optText: string) => {
    if (isOtherOption(optText)) {
      setShowTextInput(true);
      setHighlightInput(true);
      setTimeout(() => setHighlightInput(false), 2000);
      // Small delay to allow bottom sheet close animation
      setTimeout(() => textInputRef.current?.scrollIntoView(), 350);
      return;
    }
    doSubmit(optText);
  };

  const specifyLabel = voiceLanguage === "pt"
    ? "Especifique abaixo o que deseja:"
    : voiceLanguage === "es"
    ? "Especifique a continuación lo que desea:"
    : "Specify below what you want:";

  if (isFontSelection) {
    return (
      <div className="flex flex-col gap-6 w-full mt-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <p className="text-sm font-medium text-gray-500 -mb-2 tracking-wide">
          {t.selectOnlyOne}{" "}
          <strong className="text-[var(--orange)] font-semibold text-[15px]">{t.onlyOneLabel}</strong>{" "}
          {t.optionLabel}
        </p>
        <div className="flex flex-col gap-4 w-full">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 w-full cursor-pointer">
            {options.map((opt, idx) => {
              const { text: optText, key: optKey } = parseOption(opt, idx);
              const parts = optText.split(" - ");
              const fontName = parts[0].trim();
              const fontDesc = parts.slice(1).join(" - ").trim() || "";
              const fontNameClean = fontName.replace(/[^a-zA-Z0-9 ]/g, "");
              const isNoneOption =
                fontName.toLowerCase().includes("nenhuma") ||
                fontName.toLowerCase().includes("none") ||
                fontName.toLowerCase().includes("default");

              return (
                <button
                  key={optKey}
                  onClick={() => handleOptionClick(optText)}
                  disabled={isLoading || isSubmittingLocal}
                  className={`flex flex-col items-center justify-center gap-3 p-6 rounded-2xl border transition-all text-center min-h-[160px] md:min-h-[200px] group cursor-pointer ${
                    isNoneOption
                      ? "border-dashed border-gray-300 bg-gray-50 hover:bg-gray-100 hover:border-gray-400"
                      : "border-gray-200 bg-white hover:bg-[var(--orange)]/5 hover:border-[var(--orange)]/30 shadow-sm hover:-translate-y-1"
                  }`}
                  style={isNoneOption ? undefined : { fontFamily: `"${fontNameClean}", sans-serif` }}
                >
                  {isNoneOption ? (
                    <>
                      <span className="text-[28px] font-medium text-gray-400 group-hover:text-gray-600 transition-colors leading-tight">
                        Aa
                      </span>
                      <span className="text-sm text-gray-400 group-hover:text-gray-600 font-inter">
                        {fontDesc || "Padrão do Sistema"}
                      </span>
                    </>
                  ) : (
                    <>
                      <span className="text-[28px] md:text-[32px] font-semibold text-black group-hover:text-[var(--orange)] shadow-sm transition-colors leading-tight" style={{textShadow: "1px 1px 0px rgba(255,255,255,1)"}}>
                        {companyPreview}
                      </span>
                      <span className="text-xs uppercase tracking-[0.15em] text-gray-400 group-hover:text-gray-500 font-inter font-semibold mt-1">
                        {fontName}
                      </span>
                    </>
                  )}
                </button>
              );
            })}
          </div>
          {activeMessage.allowMoreOptions && (
            <div className="flex justify-start">
              <Button
                variant="ghost"
                size="lg"
                onClick={generateMoreOptions}
                disabled={isGeneratingMore || isLoading || isSubmittingLocal}
                className="rounded-full text-[var(--orange)] hover:text-[#e05221] hover:bg-[var(--orange)]/10 h-12 md:h-14 font-medium"
              >
                <RefreshCw className={`w-4 h-4 mr-2 ${isGeneratingMore ? "animate-spin" : ""}`} />
                {t.otherOptions}
              </Button>
            </div>
          )}
        </div>
        {isTextInputVisible ? (
          <div className="w-full flex flex-col items-center mt-2 animate-in fade-in slide-in-from-top-2 duration-300">
            {highlightInput && (
              <p className="text-sm font-medium text-[var(--orange)] text-center animate-pulse mb-2">
                ↓ {specifyLabel}
              </p>
            )}
            <TextAudioInput
              ref={textInputRef}
              inputText={inputText}
              setInputText={setInputText}
              onSubmit={handleLocalSend}
              isLoading={isLoading}
              isSubmittingLocal={isSubmittingLocal}
              voiceLanguage={voiceLanguage}
            />
          </div>
        ) : (
          <div className="flex justify-center mt-2 animate-in fade-in">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowTextInput(true)}
              className="text-xs text-gray-400 hover:text-gray-600 rounded-full"
            >
              + {t.moreDetails || "Adicionar detalhes"}
            </Button>
          </div>
        )}
      </div>
    );
  }

  if (useBottomSheet) {
    return (
      <div className="flex flex-col gap-4 w-full mt-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <p className="text-sm font-medium text-gray-500 tracking-wide">
          {t.selectOnlyOne}{" "}
          <strong className="text-[var(--orange)] font-semibold">{t.onlyOneLabel}</strong>{" "}
          {t.optionLabel}
        </p>
        <BottomSheetOptions
          options={options.map((opt, idx) => parseOption(opt, idx).text)}
          onSelect={handleBottomSheetSelect}
          isDisabled={isLoading || isSubmittingLocal}
          label={t.viewOptions}
        />
        {isTextInputVisible ? (
          <div className="w-full flex flex-col items-center mt-2 animate-in fade-in slide-in-from-top-2 duration-300">
            {highlightInput && (
              <p className="text-sm font-medium text-[var(--orange)] text-center animate-pulse mb-2">
                ↓ {specifyLabel}
              </p>
            )}
            <TextAudioInput
              ref={textInputRef}
              inputText={inputText}
              setInputText={setInputText}
              onSubmit={handleLocalSend}
              isLoading={isLoading}
              isSubmittingLocal={isSubmittingLocal}
              voiceLanguage={voiceLanguage}
            />
          </div>
        ) : (
          <div className="flex justify-center mt-2 animate-in fade-in">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowTextInput(true)}
              className="text-xs text-gray-400 hover:text-gray-600 rounded-full"
            >
              + {t.moreDetails || "Adicionar detalhes"}
            </Button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-6 w-full mt-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <p className="text-sm font-medium text-gray-500 -mb-2 tracking-wide">
        {t.selectOnlyOne}{" "}
        <strong className="text-[var(--orange)] font-semibold text-[15px]">{t.onlyOneLabel}</strong>{" "}
        {t.optionLabel}
      </p>
      <div className="flex flex-wrap gap-2 md:gap-3 items-center w-full">
        {options.map((opt, idx) => {
          const { text: optText, key: optKey } = parseOption(opt, idx);
          return (
            <Button
              key={optKey}
              variant="outline"
              size="lg"
              onClick={() => handleOptionClick(optText)}
              disabled={isLoading || isSubmittingLocal}
              className="rounded-full bg-white border-gray-200 hover:border-[var(--orange)]/40 hover:bg-[var(--orange)]/5 text-black shadow-sm min-h-[48px] h-12 md:h-14 md:px-6 font-medium tracking-wide transition-all active:scale-[0.97]"
            >
              {optText}
            </Button>
          );
        })}
        {activeMessage.allowMoreOptions && (
          <Button
            variant="ghost"
            size="lg"
            onClick={generateMoreOptions}
            disabled={isGeneratingMore || isLoading || isSubmittingLocal}
            className="rounded-full text-[var(--orange)] hover:text-[#e05221] hover:bg-[var(--orange)]/10 h-12 md:h-14 font-medium"
          >
            <RefreshCw className={`w-4 h-4 mr-2 ${isGeneratingMore ? "animate-spin" : ""}`} />
            {t.otherOptions}
          </Button>
        )}
      </div>
      {isTextInputVisible ? (
        <div className="w-full flex flex-col items-center mt-2 animate-in fade-in slide-in-from-top-2 duration-300">
          {highlightInput && (
            <p className="text-sm font-medium text-[var(--orange)] text-center animate-pulse mb-2">
              ↓ {specifyLabel}
            </p>
          )}
          <TextAudioInput
            ref={textInputRef}
            inputText={inputText}
            setInputText={setInputText}
            onSubmit={handleLocalSend}
            isLoading={isLoading}
            isSubmittingLocal={isSubmittingLocal}
            voiceLanguage={voiceLanguage}
          />
        </div>
      ) : (
        <div className="flex justify-center mt-2 animate-in fade-in">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setShowTextInput(true)}
            className="text-xs text-gray-400 hover:text-gray-600 rounded-full"
          >
            + {t.moreDetails || "Adicionar detalhes"}
          </Button>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Copy, Bot } from 'lucide-react';
import { toast } from 'sonner';

interface CopyButtonsProps {
  markdown: string;
  html: string;
}

export function CopyButtons({ markdown, html }: CopyButtonsProps) {
  const [copiedMd, setCopiedMd] = useState(false);
  const [copiedRich, setCopiedRich] = useState(false);

  const handleCopyMarkdown = async () => {
    try {
      await navigator.clipboard.writeText(markdown);
      setCopiedMd(true);
      toast.success('Conteúdo copiado em texto simples (Markdown)!');
      setTimeout(() => setCopiedMd(false), 2000);
    } catch (err) {
      toast.error('Erro ao copiar formato markdown');
    }
  };

  const handleCopyRichText = async () => {
    try {
      if (typeof ClipboardItem !== 'undefined') {
        const plainText = markdown.replace(/[#*`_]/g, '');
        const blobHtml = new Blob([html], { type: 'text/html' });
        const blobText = new Blob([plainText], { type: 'text/plain' });

        const item = new ClipboardItem({
          'text/html': blobHtml,
          'text/plain': blobText
        });

        await navigator.clipboard.write([item]);
      } else {
        await navigator.clipboard.writeText(markdown.replace(/[#*`_]/g, ''));
      }

      setCopiedRich(true);
      toast.success('Conteúdo copiado!');
      setTimeout(() => setCopiedRich(false), 2000);
    } catch (err) {
      try {
        await navigator.clipboard.writeText(markdown.replace(/[#*`_]/g, ''));
        setCopiedRich(true);
        toast.success('Conteúdo copiado como texto simples!');
        setTimeout(() => setCopiedRich(false), 2000);
      } catch (e) {
        toast.error('Erro ao copiar');
      }
    }
  };

  return (
    <div className="flex flex-col sm:flex-row items-center gap-2 lg:gap-3 w-full">
      <Button 
        onClick={handleCopyRichText}
        variant="outline" 
        size="sm"
        className="flex-1 w-full text-xs font-semibold bg-[var(--bg)] border-[var(--bd-strong)] text-[var(--text)] hover:bg-[var(--bg2)]"
      >
        <Copy className="w-3.5 h-3.5 mr-2" />
        {copiedRich ? 'Copiado' : 'Copiar'}
      </Button>

      <Button 
        onClick={handleCopyMarkdown}
        variant="default"
        size="sm"
        className="flex-1 w-full text-xs font-semibold bg-[var(--orange)] hover:bg-[#e8552a] text-black shadow-sm"
      >
        <Bot className="w-3.5 h-3.5 mr-2" />
        {copiedMd ? 'Pronto para IA!' : 'Copiar para IA'}
      </Button>
    </div>
  );
}

'use client';

import { useState, useMemo } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from '@/components/ui/sheet';
import { Checkbox } from '@/components/ui/checkbox';
import { format, subDays, isAfter } from 'date-fns';
import {
  Search, ExternalLink, Trash2, Copy, CheckCircle2, Clock,
  AlertCircle, FileText, Eye, CalendarDays, X, Download, Package,
} from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import { exportSessionsAsZip } from '@/lib/exportZip';
import { useDashboardLanguage } from '@/i18n/DashboardLanguageContext';

interface Session {
  id: string;
  session_name?: string;
  template_id?: string;
  template_name?: string;
  status: string;
  created_at: string;
  final_assets?: Record<string, unknown>;
  final_document?: string;
  basal_coverage?: number | null;
}

const STATUS_CONFIG: Record<string, { label: string; color: string; icon: React.ComponentType<{ className?: string }> }> = {
  finished: { label: 'Completed', color: 'text-emerald-600 bg-emerald-50 border-emerald-200', icon: CheckCircle2 },
  in_progress: { label: 'In Progress', color: 'text-amber-600 bg-amber-50 border-amber-200', icon: Clock },
  pending: { label: 'Pending', color: 'text-[var(--text3)] bg-[var(--bg2)] border-[var(--bd)]', icon: AlertCircle },
};

const FILTER_TABS = [
  { key: 'all', labelKey: 'dashboard.filterAll' },
  { key: 'finished', labelKey: 'dashboard.filterCompleted' },
  { key: 'in_progress', labelKey: 'dashboard.filterInProgress' },
  { key: 'pending', labelKey: 'dashboard.filterPending' },
];

const DATE_FILTERS = [
  { key: 'all', labelKey: 'dashboard.dateAll' },
  { key: '7', labelKey: 'dashboard.dateLast7' },
  { key: '30', labelKey: 'dashboard.dateLast30' },
  { key: '90', labelKey: 'dashboard.dateLast90' },
];

export function DashboardClient({ sessions }: { sessions: Session[] }) {
  const router = useRouter();
  const { language, t } = useDashboardLanguage();
  const [filter, setFilter] = useState('all');
  const [dateFilter, setDateFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [previewSession, setPreviewSession] = useState<Session | null>(null);
  const [selectedForExport, setSelectedForExport] = useState<Set<string>>(new Set());
  const [isExporting, setIsExporting] = useState(false);

  const filtered = useMemo(() => {
    return sessions.filter(s => {
      if (filter !== 'all' && s.status !== filter) return false;
      if (dateFilter !== 'all') {
        const days = parseInt(dateFilter);
        const cutoff = subDays(new Date(), days);
        if (!isAfter(new Date(s.created_at), cutoff)) return false;
      }
      if (search.trim()) {
        const q = search.toLowerCase();
        return (s.session_name || '').toLowerCase().includes(q) || s.id.toLowerCase().includes(q);
      }
      return true;
    });
  }, [sessions, filter, dateFilter, search]);

  const handleCopyLink = (sessionId: string) => {
    const link = `${window.location.origin}/b/${sessionId}`;
    navigator.clipboard.writeText(link);
    setCopiedId(sessionId);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleDelete = async (sessionId: string) => {
    if (!confirm('Are you sure you want to delete this briefing? This action cannot be undone.')) return;
    setDeletingId(sessionId);
    try {
      const supabase = createClient();
      await supabase.from('briefing_interactions').delete().eq('session_id', sessionId);
      await supabase.from('briefing_sessions').delete().eq('id', sessionId);
      router.refresh();
    } catch (error) {
      console.error('Failed to delete session:', error);
    } finally {
      setDeletingId(null);
    }
  };

  const getPreviewContent = (session: Session): string => {
    if (session.final_document) return session.final_document;
    const assets = session.final_assets as Record<string, unknown> | null;
    if (!assets) return '';
    if (typeof assets.document === 'string') return assets.document;
    return JSON.stringify(assets, null, 2);
  };

  // ── Export Handlers ─────────────────────────────────────────────────────────
  const toggleExportSelect = (id: string) => {
    setSelectedForExport(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleExportSelected = async () => {
    const toExport = sessions.filter(s => selectedForExport.has(s.id));
    if (toExport.length === 0) return;
    setIsExporting(true);
    try {
      await exportSessionsAsZip(toExport as Parameters<typeof exportSessionsAsZip>[0], language);
      setSelectedForExport(new Set());
    } catch (e) {
      console.error('Export error:', e);
    } finally {
      setIsExporting(false);
    }
  };

  const handleExportAll = async () => {
    setIsExporting(true);
    try {
      await exportSessionsAsZip(sessions as Parameters<typeof exportSessionsAsZip>[0], language);
    } catch (e) {
      console.error('Export error:', e);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="space-y-4">
      {/* Header + Search */}
      <div className="flex flex-col md:flex-row gap-3 items-stretch md:items-center justify-between">
        <h3 className="text-xl font-semibold text-[var(--text)]">{t('dashboard.myBriefings')}</h3>
        <div className="flex items-center gap-2 flex-1 md:justify-end">
          {/* Search */}
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[var(--text3)]" />
            <Input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder={t('dashboard.searchPlaceholder')}
              className="pl-9 bg-[var(--bg)] border-[var(--bd)] focus-visible:ring-[var(--orange)] rounded-xl h-10"
            />
            {search && (
              <button
                onClick={() => setSearch('')}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-[var(--text3)] hover:text-[var(--text)] transition-colors"
              >
                <X className="w-3.5 h-3.5" />
              </button>
            )}
          </div>

          {/* Export All */}
          <Button
            variant="outline"
            size="sm"
            onClick={handleExportAll}
            disabled={isExporting || sessions.length === 0}
            className="shrink-0 border-[var(--bd)] text-[var(--text2)] hover:text-[var(--text)] hover:bg-[var(--bg2)] rounded-xl h-10 px-3 gap-1.5"
            title="Export all briefings as ZIP"
          >
            <Package className="w-3.5 h-3.5" />
            <span className="hidden sm:inline text-xs">{t('dashboard.exportAll')}</span>
          </Button>
        </div>
      </div>

      {/* Export Selection Bar */}
      {selectedForExport.size > 0 && (
        <div className="flex items-center justify-between bg-[var(--acbg)] border border-[var(--acbd)] rounded-2xl px-4 py-3">
          <span className="text-sm text-[var(--actext)] font-medium">
            {selectedForExport.size} {t('dashboard.briefingsSelected')}
          </span>
          <div className="flex gap-2">
            <Button
              size="sm"
              variant="ghost"
              onClick={() => setSelectedForExport(new Set())}
              className="text-[var(--text3)] hover:text-[var(--text)] text-xs rounded-lg"
            >
              {t('dashboard.clear')}
            </Button>
            <Button
              size="sm"
              onClick={handleExportSelected}
              disabled={isExporting}
              className="bg-[var(--orange)] hover:bg-[#e8552a] text-black font-semibold rounded-xl text-xs gap-1.5"
            >
              <Download className="w-3.5 h-3.5" />
              {isExporting ? t('dashboard.exporting') : t('dashboard.exportZip')}
            </Button>
          </div>
        </div>
      )}

      {/* Filter Tabs + Date Filter */}
      <div className="flex flex-col sm:flex-row gap-2 sm:items-center justify-between">
        <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
          {FILTER_TABS.map(tab => (
            <Button
              key={tab.key}
              variant="ghost"
              size="sm"
              onClick={() => setFilter(tab.key)}
              className={`rounded-full px-4 shrink-0 transition-all ${
                filter === tab.key
                  ? 'bg-[var(--acbg)] text-[var(--actext)] border border-[var(--acbd)]'
                  : 'text-[var(--text3)] hover:text-[var(--text)] hover:bg-[var(--bg2)] border border-transparent'
              }`}
            >
              {t(tab.labelKey)}
              {tab.key !== 'all' && (
                <span className="ml-1.5 text-xs opacity-70">
                  {sessions.filter(s => s.status === tab.key).length}
                </span>
              )}
            </Button>
          ))}
        </div>

        <div className="flex items-center gap-1.5 shrink-0">
          <CalendarDays className="w-3.5 h-3.5 text-[var(--text3)]" />
          <div className="flex gap-1 overflow-x-auto no-scrollbar">
            {DATE_FILTERS.map(d => (
              <button
                key={d.key}
                onClick={() => setDateFilter(d.key)}
                className={`text-xs px-3 py-1.5 rounded-full transition-all whitespace-nowrap ${
                  dateFilter === d.key
                    ? 'bg-[var(--text)] text-[var(--bg)] font-semibold'
                    : 'text-[var(--text3)] hover:text-[var(--text)] hover:bg-[var(--bg2)]'
                }`}
              >
                {t(d.labelKey)}
              </button>
            ))}
          </div>
        </div>
      </div>

      {filtered.length !== sessions.length && (
        <p className="text-xs text-[var(--text3)]">
          {t('dashboard.showing')} <span className="text-[var(--text)] font-medium">{filtered.length}</span> {t('dashboard.of')} {sessions.length} {t('dashboard.briefings')}
        </p>
      )}

      {/* Session Cards */}
      {filtered.length === 0 ? (
        <div className="bg-[var(--bg2)] border border-[var(--bd)] rounded-xl">
          <div className="text-center py-12 text-[var(--text3)]">
            <FileText className="w-10 h-10 mx-auto mb-3 opacity-50" />
            <p className="text-lg">{t('dashboard.noBriefings')}</p>
          </div>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map(session => {
            const statusInfo = STATUS_CONFIG[session.status] || STATUS_CONFIG.pending;
            const StatusIcon = statusInfo.icon;
            const hasDocument = !!(session.final_assets as Record<string, unknown> | null)?.document || !!session.final_document;
            const isChecked = selectedForExport.has(session.id);

            return (
              <div
                key={session.id}
                className={`bg-[var(--bg)] border rounded-xl hover:border-[var(--bd-strong)] transition-all duration-200 group ${
                  isChecked ? 'border-[var(--acbd)] bg-[var(--acbg)]' : 'border-[var(--bd)]'
                }`}
              >
                <div className="py-4 px-4 md:px-6">
                  <div className="flex items-center gap-3 md:gap-6">
                    {/* Export Checkbox */}
                    <Checkbox
                      checked={isChecked}
                      onCheckedChange={() => toggleExportSelect(session.id)}
                      className="shrink-0 opacity-40 group-hover:opacity-100 transition-opacity data-[state=checked]:opacity-100"
                    />

                    {/* Info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1 flex-wrap">
                        <h4 className="font-semibold text-[var(--text)] truncate text-sm md:text-base">
                          {session.session_name || 'Untitled Briefing'}
                        </h4>
                        <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[11px] font-medium border ${statusInfo.color}`}>
                          <StatusIcon className="w-3 h-3" />
                          {statusInfo.label}
                        </span>
                      </div>
                      <div className="flex items-center gap-3 text-xs text-[var(--text3)]">
                        <span className="font-mono">{session.id.slice(0, 8)}...</span>
                        <span>•</span>
                        <span>{format(new Date(session.created_at), 'MMM dd, yyyy')}</span>
                        {session.status === 'in_progress' && session.basal_coverage != null && (
                          <>
                            <span>•</span>
                            <div className="flex items-center gap-1.5">
                              <div className="w-12 h-1 bg-[var(--bg3)] rounded-full overflow-hidden">
                                <div
                                  className="h-full bg-[var(--orange)] rounded-full transition-all"
                                  style={{ width: `${Math.min(100, Math.round(Number(session.basal_coverage) * 100))}%` }}
                                />
                              </div>
                              <span className="text-[10px] text-[var(--orange)] font-mono">
                                {Math.round(Number(session.basal_coverage) * 100)}%
                              </span>
                            </div>
                          </>
                        )}
                      </div>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center gap-1 shrink-0">
                      {hasDocument && (
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setPreviewSession(session)}
                          className="text-[var(--text3)] hover:text-[var(--text)] hover:bg-[var(--bg2)] rounded-lg text-xs"
                          title="Quick preview"
                        >
                          <Eye className="w-3.5 h-3.5" />
                        </Button>
                      )}
                      <Link href={`/dashboard/${session.id}`}>
                        <Button
                          variant="ghost"
                          size="sm"
                          className="text-[var(--actext)] hover:bg-[var(--acbg)] rounded-lg text-xs"
                        >
                          <ExternalLink className="w-3.5 h-3.5 mr-1" />
                          <span className="hidden sm:inline">View</span>
                        </Button>
                      </Link>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleCopyLink(session.id)}
                        className={`rounded-lg text-xs hidden sm:flex ${
                          copiedId === session.id
                            ? 'text-emerald-500 bg-emerald-50'
                            : 'text-[var(--text3)] hover:text-[var(--text)] hover:bg-[var(--bg2)]'
                        }`}
                      >
                        <Copy className="w-3.5 h-3.5 mr-1" />
                        {copiedId === session.id ? t('dashboard.copied') : t('dashboard.link')}
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleDelete(session.id)}
                        disabled={deletingId === session.id}
                        className="text-[var(--text3)] hover:text-red-500 hover:bg-red-50 rounded-lg text-xs"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </Button>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Quick Preview Sheet */}
      <Sheet open={!!previewSession} onOpenChange={(open) => !open && setPreviewSession(null)}>
        <SheetContent
          side="right"
          className="w-full sm:max-w-2xl bg-[var(--bg)] border-[var(--bd)] overflow-y-auto p-0"
        >
          {previewSession && (
            <>
              <SheetHeader className="p-6 pb-4 border-b border-[var(--bd)] sticky top-0 bg-[var(--bg)] z-10">
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0">
                    <SheetTitle className="text-[var(--text)] font-semibold text-base truncate">
                      {previewSession.session_name || t('dashboard.untitled')}
                    </SheetTitle>
                    <p className="text-xs text-[var(--text3)] mt-0.5">
                      {format(new Date(previewSession.created_at), 'MMM dd, yyyy • HH:mm')}
                    </p>
                  </div>
                  <div className="flex gap-2 shrink-0">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={async () => {
                        setIsExporting(true);
                        try {
                          await exportSessionsAsZip([previewSession] as Parameters<typeof exportSessionsAsZip>[0], language);
                        } finally {
                          setIsExporting(false);
                        }
                      }}
                      disabled={isExporting}
                      className="border-[var(--bd)] text-[var(--text2)] hover:text-[var(--text)] rounded-xl text-xs gap-1"
                    >
                      <Download className="w-3.5 h-3.5" />
                      {t('dashboard.export')}
                    </Button>
                    <Link href={`/dashboard/${previewSession.id}`}>
                      <Button
                        size="sm"
                        className="bg-[var(--orange)] hover:bg-[#e8552a] text-black font-semibold rounded-xl text-xs"
                      >
                        <ExternalLink className="w-3.5 h-3.5 mr-1.5" />
                        {t('dashboard.openFull')}
                      </Button>
                    </Link>
                  </div>
                </div>
              </SheetHeader>

              <div className="p-6">
                {getPreviewContent(previewSession) ? (
                  <div className="prose prose-sm max-w-none">
                    <pre className="whitespace-pre-wrap text-sm text-[var(--text2)] leading-relaxed font-sans bg-transparent p-0 border-0">
                      {getPreviewContent(previewSession)}
                    </pre>
                  </div>
                ) : (
                  <div className="text-center text-[var(--text3)] py-12">
                    <FileText className="w-10 h-10 mx-auto mb-3 opacity-40" />
                    <p>{t('dashboard.noContent')}</p>
                  </div>
                )}
              </div>
            </>
          )}
        </SheetContent>
      </Sheet>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import {
  Share2, CheckCircle2, Copy, Package, Brain, Palette, Cpu,
